tree = {
    'A': ['B', 'C', 'D'],
    'B': ['E'],
    'C': ['F'],
    'D': ['G', 'H'],
    'E': ['I', 'J'],
    'F': [], 'G': [], 'I': [], 'J': [], 'K': [],
    'H': ['K'],
}

def dfs(node, visited=None):
    if visited is None:
        visited = []
    visited.append(node)
    for child in tree.get(node, []):
        dfs(child, visited)
    return visited

def bfs(start):
    from collections import deque
    visited = []
    queue = deque([start])
    seen = {start}
    while queue:
        node = queue.popleft()
        visited.append(node)
        for child in tree.get(node, []):
            if child not in seen:
                seen.add(child)
                queue.append(child)
    return visited

print("DFS:", ' → '.join(dfs('A')))
print("BFS:", ' → '.join(bfs('A')))
